type userWhere[Q sqlite.Filterable] struct {
	ID             sqlite.WhereMod[Q, string]
	Username       sqlite.WhereMod[Q, string]
	Password       sqlite.WhereMod[Q, string]
	Active         sqlite.WhereMod[Q, bool]
	Timezone       sqlite.WhereNullMod[Q, string]
	TwofaSecret    sqlite.WhereNullMod[Q, string]
	TwofaStatus    sqlite.WhereMod[Q, bool]
	TwofaLastToken sqlite.WhereNullMod[Q, string]
	CreatedDate    sqlite.WhereMod[Q, time.Time]
}

func (userWhere[Q]) AliasedAs(alias string) userWhere[Q] {
	return buildUserWhere[Q](buildUserColumns(alias))
}

func buildUserWhere[Q sqlite.Filterable](cols userColumns) userWhere[Q] {
	return userWhere[Q]{
		ID:             sqlite.Where[Q, string](cols.ID),
		Username:       sqlite.Where[Q, string](cols.Username),
		Password:       sqlite.Where[Q, string](cols.Password),
		Active:         sqlite.Where[Q, bool](cols.Active),
		Timezone:       sqlite.WhereNull[Q, string](cols.Timezone),
		TwofaSecret:    sqlite.WhereNull[Q, string](cols.TwofaSecret),
		TwofaStatus:    sqlite.Where[Q, bool](cols.TwofaStatus),
		TwofaLastToken: sqlite.WhereNull[Q, string](cols.TwofaLastToken),
		CreatedDate:    sqlite.Where[Q, time.Time](cols.CreatedDate),
	}
}

func (o *User) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "APIKeys":
		rels, ok := retrieved.(APIKeySlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.APIKeys = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "DockerHosts":
		rels, ok := retrieved.(DockerHostSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.DockerHosts = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "Maintenances":
		rels, ok := retrieved.(MaintenanceSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.Maintenances = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "Monitors":
		rels, ok := retrieved.(MonitorSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.Monitors = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "Notifications":
		rels, ok := retrieved.(NotificationSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.Notifications = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "Proxies":
		rels, ok := retrieved.(ProxySlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.Proxies = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	case "RemoteBrowsers":
		rels, ok := retrieved.(RemoteBrowserSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.RemoteBrowsers = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.User = o
			}
		}
		return nil
	default:
		return fmt.Errorf("user has no relationship %q", name)
	}
}

