// userC is where relationship counts are stored.
type userC struct {
	APIKeys        *int64
	DockerHosts    *int64
	Maintenances   *int64
	Monitors       *int64
	Notifications  *int64
	Proxies        *int64
	RemoteBrowsers *int64
}

// PreloadCount sets a count in the C struct by name
func (o *User) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "APIKeys":
		o.C.APIKeys = &count
	case "DockerHosts":
		o.C.DockerHosts = &count
	case "Maintenances":
		o.C.Maintenances = &count
	case "Monitors":
		o.C.Monitors = &count
	case "Notifications":
		o.C.Notifications = &count
	case "Proxies":
		o.C.Proxies = &count
	case "RemoteBrowsers":
		o.C.RemoteBrowsers = &count
	}
	return nil
}

