type userCountThenLoader[Q orm.Loadable] struct {
	APIKeys        func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	DockerHosts    func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Maintenances   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Monitors       func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Notifications  func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Proxies        func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	RemoteBrowsers func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildUserCountThenLoader[Q orm.Loadable]() userCountThenLoader[Q] {
	type APIKeysCountInterface interface {
		LoadCountAPIKeys(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type DockerHostsCountInterface interface {
		LoadCountDockerHosts(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type MaintenancesCountInterface interface {
		LoadCountMaintenances(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type MonitorsCountInterface interface {
		LoadCountMonitors(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type NotificationsCountInterface interface {
		LoadCountNotifications(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type ProxiesCountInterface interface {
		LoadCountProxies(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type RemoteBrowsersCountInterface interface {
		LoadCountRemoteBrowsers(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return userCountThenLoader[Q]{
		APIKeys: countThenLoadBuilder[Q](
			"APIKeys",
			func(ctx context.Context, exec bob.Executor, retrieved APIKeysCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountAPIKeys(ctx, exec, mods...)
			},
		),
		DockerHosts: countThenLoadBuilder[Q](
			"DockerHosts",
			func(ctx context.Context, exec bob.Executor, retrieved DockerHostsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountDockerHosts(ctx, exec, mods...)
			},
		),
		Maintenances: countThenLoadBuilder[Q](
			"Maintenances",
			func(ctx context.Context, exec bob.Executor, retrieved MaintenancesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountMaintenances(ctx, exec, mods...)
			},
		),
		Monitors: countThenLoadBuilder[Q](
			"Monitors",
			func(ctx context.Context, exec bob.Executor, retrieved MonitorsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountMonitors(ctx, exec, mods...)
			},
		),
		Notifications: countThenLoadBuilder[Q](
			"Notifications",
			func(ctx context.Context, exec bob.Executor, retrieved NotificationsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountNotifications(ctx, exec, mods...)
			},
		),
		Proxies: countThenLoadBuilder[Q](
			"Proxies",
			func(ctx context.Context, exec bob.Executor, retrieved ProxiesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountProxies(ctx, exec, mods...)
			},
		),
		RemoteBrowsers: countThenLoadBuilder[Q](
			"RemoteBrowsers",
			func(ctx context.Context, exec bob.Executor, retrieved RemoteBrowsersCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountRemoteBrowsers(ctx, exec, mods...)
			},
		),
	}
}

// LoadCountAPIKeys loads the count of APIKeys into the C struct
func (o *User) LoadCountAPIKeys(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	count, err := o.APIKeys(mods...).Count(ctx, exec)
	if err != nil {
		return err
	}

	o.C.APIKeys = &count
	return nil
}

// LoadCountAPIKeys loads the count of APIKeys for a slice in a single batch query
func (os UserSlice) LoadCountAPIKeys(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs
	PKArgSlice := make([]bob.Expression, 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		PKArgSlice = append(PKArgSlice, sqlite.Arg(o.ID))
	}
	PKArgExpr := sqlite.Group(PKArgSlice...)

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    string
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			APIKeys.Columns.UserID.As("id"),
			sqlite.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(APIKeys.NameAs()),

		// WHERE fk IN (parent PKs)
		sm.Where(APIKeys.Columns.UserID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(APIKeys.Columns.UserID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		sqlite.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[string]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.APIKeys = &count
	}

	return nil
}

