type userJoins[Q dialect.Joinable] struct {
	typ            string
	APIKeys        modAs[Q, apiKeyColumns]
	DockerHosts    modAs[Q, dockerHostColumns]
	Maintenances   modAs[Q, maintenanceColumns]
	Monitors       modAs[Q, monitorColumns]
	Notifications  modAs[Q, notificationColumns]
	Proxies        modAs[Q, proxyColumns]
	RemoteBrowsers modAs[Q, remoteBrowserColumns]
}

func (j userJoins[Q]) aliasedAs(alias string) userJoins[Q] {
	return buildUserJoins[Q](buildUserColumns(alias), j.typ)
}

func buildUserJoins[Q dialect.Joinable](cols userColumns, typ string) userJoins[Q] {
	return userJoins[Q]{
		typ: typ,
		APIKeys: modAs[Q, apiKeyColumns]{
			c: APIKeys.Columns,
			f: func(to apiKeyColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, APIKeys.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		DockerHosts: modAs[Q, dockerHostColumns]{
			c: DockerHosts.Columns,
			f: func(to dockerHostColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, DockerHosts.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Maintenances: modAs[Q, maintenanceColumns]{
			c: Maintenances.Columns,
			f: func(to maintenanceColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Maintenances.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Monitors: modAs[Q, monitorColumns]{
			c: Monitors.Columns,
			f: func(to monitorColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Monitors.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Notifications: modAs[Q, notificationColumns]{
			c: Notifications.Columns,
			f: func(to notificationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Notifications.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Proxies: modAs[Q, proxyColumns]{
			c: Proxies.Columns,
			f: func(to proxyColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Proxies.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		RemoteBrowsers: modAs[Q, remoteBrowserColumns]{
			c: RemoteBrowsers.Columns,
			f: func(to remoteBrowserColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, RemoteBrowsers.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
